function longestObstacleCourse(obstacles) {
    const dp = [];
    const ans = new Array(obstacles.length).fill(0);

    for (let obstacle of obstacles) {
        let index = binarySearch(dp, obstacle);
        ans[index] = index + 1;
        if (index === dp.length) {
            dp.push(obstacle);
        } else {
            dp[index] = obstacle;
        }
    }

    return ans;
}

function binarySearch(arr, target) {
    let left = 0;
    let right = arr.length - 1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);

        if (arr[mid] === target) {
            return mid;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return left;
}
```

    The main idea of the algorithm is to use dynamic programming to build a list of subproblems (dp), where dp[i] represents the smallest height of the i-th obstacle in a valid course of length i+1.

For each obstacle, we do a binary search in our dp list to find the index where the current obstacle should be put, updating the dp list accordingly. We save the index + 1 in our ans list, since this represents the length of the longest obstacle course including the current obstacle.

Finally, the dynamic programming table is updated with the index found, and we return ans.

