import java.util.Arrays;

public int[] longestObstacleCourse(int[] obstacles) {
    int[] dp = new int[obstacles.length];
    int len = 0;

    for (int obstacle : obstacles) {
        int i = Arrays.binarySearch(dp, 0, len, obstacle);
        if (i < 0) {
            i = -(i + 1);
        }
        dp[i] = obstacle;
        if (i == len) {
            len++;
        }
    }

    return dp;
}
```

